import { _decorator, Component, director, Node, EditBox, Button, Label } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('LoginScene')
export class LoginScene extends Component {
    @property(EditBox)
    phoneInput: EditBox = null;
    
    @property(EditBox)
    codeInput: EditBox = null;
    
    @property(Button)
    loginBtn: Button = null;
    
    @property(Button)
    wxLoginBtn: Button = null;
    
    @property(Label)
    tipLabel: Label = null;
    
    onLoad() {
        this.loginBtn.node.on(Button.EventType.CLICK, this.onLogin, this);
        this.wxLoginBtn.node.on(Button.EventType.CLICK, this.onWXLogin, this);
    }
    
    async onLogin() {
        const phone = this.phoneInput.string;
        const code = this.codeInput.string;
        
        if (!phone || phone.length !== 11) {
            this.showTip('请输入正确的手机号');
            return;
        }
        
        GameManager.getInstance().showLoading('登录中...');
        
        try {
            const result = await GameManager.getInstance().network.request('/api/auth/login', {
                phone: phone,
                code: code
            });
            
            if (result.success) {
                GameManager.getInstance().playerData.setToken(result.token);
                GameManager.getInstance().playerData.setUserInfo(result.user);
                director.loadScene('MainScene');
            } else {
                this.showTip(result.message || '登录失败');
            }
        } catch (error) {
            this.showTip('网络错误，请重试');
        } finally {
            GameManager.getInstance().hideLoading();
        }
    }
    
    async onWXLogin() {
        // 微信登录（Web版使用扫码）
        this.showTip('微信登录功能开发中...');
    }
    
    showTip(msg: string) {
        this.tipLabel.string = msg;
        this.tipLabel.node.active = true;
        setTimeout(() => {
            this.tipLabel.node.active = false;
        }, 3000);
    }
}
